import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine().trim(); // Read full line and remove leading/trailing whitespaces

        // Creating a fixed size array with buffer size 10
        char[] buffer = new char[10];

        // Copying a safe portion of the user input into the buffer
        int length = Math.min(input.length(), buffer.length);
        input.getChars(0, length, buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
